@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterSequenceTypeVtxo: FfiConverterRustBuffer {
    typealias SwiftType = [Vtxo]

    public static func write(_ value: [Vtxo], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterTypeVtxo.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [Vtxo] {
        let len: Int32 = try readInt(&buf)
        var seq = [Vtxo]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterTypeVtxo.read(from: &buf))
        }
        return seq
    }
}

private enum InitializationResult {
